// // This module converts a 5-bit binary input to a 3-bit binary output indicating the temperature status.
// The temperature ranges are defined as follows:
// - Low for 0-15°C
// - Medium for 16-25°C
// - High for 26-31°C
// If the input temperature is out of range (>31°C), the output should be 111 (Valid).

module temperature_sensor(
    input [4:0] temp,
    output reg [2:0] status
);

always @(*) begin
    if (temp <= 5'd15) begin
        status = 3'b000; // Low
    end else if (temp <= 5'd25) begin
        status = 3'b001; // Medium
    end else if (temp <= 5'd31) begin
        status = 3'b010; // High
    end else begin
        status = 3'b111; // Invalid
    end
end

endmodule

